def get_db():
    conn = sqlite3.connect(DB_PATH, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    conn = get_db()
    cur = conn.cursor()
    cur.execute(
        """
        CREATE TABLE IF NOT EXISTS contributions (
            id TEXT PRIMARY KEY,
            source_type TEXT NOT NULL,
            image_path TEXT NOT NULL,
            label TEXT NOT NULL,
            uploaded_at TEXT NOT NULL,
            meta_json TEXT
        )
        """
    )
    cur.execute(
        """
        CREATE TABLE IF NOT EXISTS training_runs (
            id TEXT PRIMARY KEY,
            started_at TEXT NOT NULL,
            completed_at TEXT,
            status TEXT NOT NULL,
            epochs INTEGER,
            batch_size INTEGER,
            val_accuracy REAL,
            train_count INTEGER,
            class_count INTEGER,
            details_json TEXT
        )
        """
    )
    conn.commit()
    conn.close()


init_db()


class TrainRequest(BaseModel):
    epochs: int = 5
    batch_size: int = 32
    image_size: int = 128
    validation_split: float = 0.2


def allowed_image_filename(name: str) -> bool:
    ext = os.path.splitext(name.lower())[1]
    return ext in {".jpg", ".jpeg", ".png", ".bmp", ".gif", ".webp"}


def save_image_bytes(image_bytes: bytes, label: str, source_type: str, meta: Optional[dict] = None) -> str:
    contribution_id = str(uuid.uuid4())
    label_safe = label.strip().replace("/", "_").replace("\\", "_")
    target_dir = os.path.join(IMAGES_DIR, label_safe)
    os.makedirs(target_dir, exist_ok=True)
    image_path = os.path.join(target_dir, f"{contribution_id}.png")

    img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    img.save(image_path, format="PNG")

    conn = get_db()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO contributions (id, source_type, image_path, label, uploaded_at, meta_json)
        VALUES (?, ?, ?, ?, ?, ?)
        """,
        (
            contribution_id,
            source_type,
            image_path,
            label_safe,
            datetime.utcnow().isoformat(),
            json.dumps(meta or {}),
        ),
    )
    conn.commit()
    conn.close()
    return contribution_id


def import_csv_dataset(csv_path: str, source_type: str = "csv_upload") -> Tuple[int, List[str]]:
    df = pd.read_csv(csv_path)
    required_cols = {"image_path", "label"}
    if not required_cols.issubset(df.columns):
        raise ValueError("CSV must include columns: image_path,label")

    imported = 0
    labels = set()

    base_dir = os.path.dirname(csv_path)
    for _, row in df.iterrows():
        image_ref = str(row["image_path"]).strip()
        label = str(row["label"]).strip()
        if not image_ref or not label:
            continue

        image_path = image_ref
        if not os.path.isabs(image_path):
            image_path = os.path.join(base_dir, image_ref)

        if not os.path.exists(image_path):
            continue

        with open(image_path, "rb") as f:
            image_bytes = f.read()
        save_image_bytes(image_bytes, label, source_type, meta={"original_path": image_ref})
        imported += 1
        labels.add(label)

    return imported, sorted(labels)


def import_zip_csv_dataset(zip_bytes: bytes) -> Tuple[int, List[str]]:
    extract_dir = os.path.join(UPLOADS_DIR, str(uuid.uuid4()))
    os.makedirs(extract_dir, exist_ok=True)
    zip_path = os.path.join(extract_dir, "dataset.zip")
    with open(zip_path, "wb") as f:
        f.write(zip_bytes)

    with zipfile.ZipFile(zip_path, "r") as zf:
        zf.extractall(extract_dir)

    csv_candidates = []
    for root, _, files in os.walk(extract_dir):
        for file in files:
            if file.lower().endswith(".csv"):
                csv_candidates.append(os.path.join(root, file))

    if not csv_candidates:
        raise ValueError("ZIP must contain at least one CSV file")

    imported_total = 0
    labels_total = set()
    for csv_file in csv_candidates:
        imported, labels = import_csv_dataset(csv_file, source_type="zip_csv_upload")
        imported_total += imported
        labels_total.update(labels)

    return imported_total, sorted(labels_total)


def load_contributions(image_size: int, validation_split: float):
    conn = get_db()
    rows = conn.execute("SELECT image_path, label FROM contributions").fetchall()
    conn.close()

    if not rows:
        raise ValueError("No training contributions found")

    image_arrays = []
    labels = []

    for row in rows:
        image_path = row["image_path"]
        label = row["label"]
        if not os.path.exists(image_path):
            continue
        img = Image.open(image_path).convert("RGB").resize((image_size, image_size))
        arr = np.asarray(img, dtype=np.float32) / 255.0
        image_arrays.append(arr)
        labels.append(label)

    if len(image_arrays) < 2:
        raise ValueError("Need at least 2 valid images to train")

    X = np.array(image_arrays, dtype=np.float32)
    class_names = sorted(list(set(labels)))
    label_to_idx = {name: idx for idx, name in enumerate(class_names)}
    y = np.array([label_to_idx[label] for label in labels], dtype=np.int32)

    indices = np.arange(len(X))
    np.random.shuffle(indices)
    X = X[indices]
    y = y[indices]

    split_idx = max(1, int(len(X) * (1 - validation_split)))
    if split_idx >= len(X):
        split_idx = len(X) - 1

    X_train, X_val = X[:split_idx], X[split_idx:]
    y_train, y_val = y[:split_idx], y[split_idx:]

    return X_train, X_val, y_train, y_val, class_names


def build_model(image_size: int, num_classes: int) -> keras.Model:
    model = keras.Sequential(
        [
            layers.Input(shape=(image_size, image_size, 3)),
            layers.Conv2D(32, 3, activation="relu"),
            layers.MaxPooling2D(),
            layers.Conv2D(64, 3, activation="relu"),
            layers.MaxPooling2D(),
            layers.Conv2D(128, 3, activation="relu"),
            layers.MaxPooling2D(),
            layers.Flatten(),
            layers.Dropout(0.3),
            layers.Dense(128, activation="relu"),
            layers.Dense(num_classes, activation="softmax"),
        ]
    )
    model.compile(
        optimizer="adam",
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model


def record_training_run(run_id: str, status: str, epochs: int, batch_size: int, details: dict = None,
                        completed_at: Optional[str] = None, val_accuracy: Optional[float] = None,
                        train_count: Optional[int] = None, class_count: Optional[int] = None):
    conn = get_db()
    cur = conn.cursor()
    existing = cur.execute("SELECT id FROM training_runs WHERE id = ?", (run_id,)).fetchone()
    if existing:
        cur.execute(
            """
            UPDATE training_runs
            SET completed_at=?, status=?, epochs=?, batch_size=?, val_accuracy=?, train_count=?, class_count=?, details_json=?
            WHERE id=?
            """,
            (
                completed_at,
                status,
                epochs,
                batch_size,
                val_accuracy,
                train_count,
                class_count,
                json.dumps(details or {}),
                run_id,
            ),
        )
    else:
        cur.execute(
            """
            INSERT INTO training_runs
            (id, started_at, status, epochs, batch_size, details_json)
            VALUES (?, ?, ?, ?, ?, ?)
            """,
            (
                run_id,
                datetime.utcnow().isoformat(),
                status,
                epochs,
                batch_size,
                json.dumps(details or {}),
            ),
        )
    conn.commit()
    conn.close()


