@app.post("/upload/image")
async def upload_image(label: str = Form(...), file: UploadFile = File(...)):
    if not label.strip():
        raise HTTPException(status_code=400, detail="Label is required")
    if not allowed_image_filename(file.filename or ""):
        raise HTTPException(status_code=400, detail="Unsupported image file type")
    content = await file.read()
    contribution_id = save_image_bytes(content, label, source_type="single_image_upload")
    return {"message": "Contribution saved", "contribution_id": contribution_id, "label": label}


@app.post("/upload/csv")
async def upload_csv(file: UploadFile = File(...)):
    if not (file.filename or "").lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="File must be a CSV")
    upload_id = str(uuid.uuid4())
    target_path = os.path.join(UPLOADS_DIR, f"{upload_id}.csv")
    with open(target_path, "wb") as f:
        f.write(await file.read())

    try:
        imported, labels = import_csv_dataset(target_path)
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))

    return {
        "message": "CSV dataset imported",
        "imported_examples": imported,
        "labels": labels,
    }


@app.post("/upload/zip")
async def upload_zip(file: UploadFile = File(...)):
    if not (file.filename or "").lower().endswith(".zip"):
        raise HTTPException(status_code=400, detail="File must be a ZIP")
    try:
        imported, labels = import_zip_csv_dataset(await file.read())
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))

    return {
        "message": "ZIP dataset imported",
        "imported_examples": imported,
        "labels": labels,
    }


@app.post("/train")
def train_model(req: TrainRequest):
    if req.epochs < 1 or req.batch_size < 1:
        raise HTTPException(status_code=400, detail="epochs and batch_size must be positive")
    if not (0.05 <= req.validation_split <= 0.5):
        raise HTTPException(status_code=400, detail="validation_split must be between 0.05 and 0.5")

    if not TRAINING_LOCK.acquire(blocking=False):
        raise HTTPException(status_code=409, detail="Training already in progress")

    run_id = str(uuid.uuid4())
    record_training_run(run_id, "running", req.epochs, req.batch_size, details=req.dict())

    try:
        X_train, X_val, y_train, y_val, class_names = load_contributions(req.image_size, req.validation_split)
        model = build_model(req.image_size, len(class_names))

        callbacks = [
            keras.callbacks.EarlyStopping(
                monitor="val_accuracy",
                patience=2,
                restore_best_weights=True,
            )
        ]

        history = model.fit(
            X_train,
            y_train,
            validation_data=(X_val, y_val),
            epochs=req.epochs,
            batch_size=req.batch_size,
            verbose=1,
            callbacks=callbacks,
        )

        eval_results = model.evaluate(X_val, y_val, verbose=0)
        val_accuracy = float(eval_results[1])

        model.save(MODEL_PATH)
        with open(LABELS_PATH, "w", encoding="utf-8") as f:
            json.dump(class_names, f)

        record_training_run(
            run_id=run_id,
            status="completed",
            epochs=req.epochs,
            batch_size=req.batch_size,
            completed_at=datetime.utcnow().isoformat(),
            val_accuracy=val_accuracy,
            train_count=int(len(X_train) + len(X_val)),
            class_count=len(class_names),
            details={
                "history": {k: [float(x) for x in v] for k, v in history.history.items()},
                "labels": class_names,
                "image_size": req.image_size,
            },
        )

        return {
            "message": "Training completed",
            "run_id": run_id,
            "validation_accuracy": val_accuracy,
            "classes": class_names,
            "trained_examples": int(len(X_train) + len(X_val)),
        }
    except ValueError as e:
        record_training_run(
            run_id=run_id,
            status="failed",
            epochs=req.epochs,
            batch_size=req.batch_size,
            completed_at=datetime.utcnow().isoformat(),
            details={"error": str(e)},
        )
        raise HTTPException(status_code=400, detail=str(e))
    except Exception as e:
        record_training_run(
            run_id=run_id,
            status="failed",
            epochs=req.epochs,
            batch_size=req.batch_size,
            completed_at=datetime.utcnow().isoformat(),
            details={"error": str(e)},
        )
        raise HTTPException(status_code=500, detail=str(e))
    finally:
        TRAINING_LOCK.release()


@app.post("/predict")
async def predict(file: UploadFile = File(...), image_size: int = Form(128)):
    if not os.path.exists(MODEL_PATH) or not os.path.exists(LABELS_PATH):
        raise HTTPException(status_code=404, detail="No trained model found")
    if not allowed_image_filename(file.filename or ""):
        raise HTTPException(status_code=400, detail="Unsupported image file type")

    model = keras.models.load_model(MODEL_PATH)
    with open(LABELS_PATH, "r", encoding="utf-8") as f:
        class_names = json.load(f)

    img_bytes = await file.read()
    img = Image.open(io.BytesIO(img_bytes)).convert("RGB").resize((image_size, image_size))
    arr = np.asarray(img, dtype=np.float32) / 255.0
    arr = np.expand_dims(arr, axis=0)

    preds = model.predict(arr, verbose=0)[0]
    idx = int(np.argmax(preds))
    return {
        "predicted_label": class_names[idx],
        "confidence": float(preds[idx]),
        "scores": {class_names[i]: float(preds[i]) for i in range(len(class_names))},
    }


@app.get("/contributions")
def list_contributions(limit: int = 100):
    conn = get_db()
    rows = conn.execute(
        "SELECT id, source_type, image_path, label, uploaded_at, meta_json FROM contributions ORDER BY uploaded_at DESC LIMIT ?",
        (limit,),
    ).fetchall()
    conn.close()
    return {
        "items": [
            {
                "id": row["id"],
                "source_type": row["source_type"],
                "image_path": row["image_path"],
                "label": row["label"],
                "uploaded_at": row["uploaded_at"],
                "meta": json.loads(row["meta_json"] or "{}"),
            }
            for row in rows
        ]
    }


